{ config, pkgs, meta, ... }:
{
  services.openiscsi = {
    enable = true;
    name = "iqn.2016-04.com.open-iscsi:${meta.hostname}";
  };

  systemd.tmpfiles.rules = [
    "L+ /usr/local/bin - - - - /run/current-system/sw/bin/"
  ];
}

{
  disko.devices = {
    disk = {
      main = {
        type = "disk";
        device = "/dev/sda";
        content = {
          type = "gpt";
          partitions = {
            bios = {
              size = "1M";
              type = "EF02";
            };
            ESP = {
              size = "512M";
              type = "EF00";
              content = {
                type = "filesystem";
                format = "vfat";
                mountpoint = "/boot";
              };
            };
            root = {
              size = "100%";
              content = {
                type = "filesystem";
                format = "ext4";
                mountpoint = "/";
              };
            };
          };
        };
      };
    };
  };
}

{ ... }:
{
  documentation.enable = false;

  nix.settings = {
    experimental-features = [ "nix-command" "flakes" ];
    trusted-users = [ "root" "@wheel" ];
  };

  programs.ssh.extraConfig = ''
    Host github.com
      IdentityFile /etc/ssh/ssh_host_ed25519_key
      IdentitiesOnly yes
  '';
}

{ lib, meta, ... }:
{
  imports = [ ./common.nix ];

  services.k3s = {
    enable = true;
    role = "agent";
    serverAddr = lib.mkDefault "https://10.0.0.10:6443";
    tokenFile = "/etc/k3s/token";
    extraFlags = [ "--node-label=node.kubernetes.io/role=worker" ];
  };

  networking.firewall.allowedTCPPorts = [ 10250 ];
  networking.firewall.allowedUDPPorts = [ 8472 ];
}

{ config, pkgs, meta, ... }:
{
  systemd.services.rollback-gate = {
    description = "NixOS dead-man's switch health gate";
    after = [ "k3s.service" "network-online.target" ];
    wants = [ "network-online.target" ];

    unitConfig = {
      ConditionPathExists = "/var/lib/rancher/k3s/agent/kubelet.kubeconfig";
    };

    serviceConfig = {
      Type = "oneshot";
      ExecStart = pkgs.writeShellScript "rollback-gate-check" ''
        set -euo pipefail
        ${pkgs.systemd}/bin/systemctl is-active k3s.service
        kc=/etc/rancher/k3s/k3s.yaml
        if [ ! -f "$kc" ]; then kc=/var/lib/rancher/k3s/agent/kubelet.kubeconfig; fi
        status=$(KUBECONFIG=$kc ${pkgs.k3s}/bin/kubectl get node "${meta.hostname}" \
          -o jsonpath='{.status.conditions[?(@.type=="Ready")].status}')
        [ "$status" = "True" ]
      '';
      FailureAction = "reboot-force";
      TimeoutStartSec = "120s";
    };
  };

  systemd.timers.rollback-gate = {
    description = "Timer driving the rollback-gate health gate";
    wantedBy = [ "multi-user.target" ];
    timerConfig = {
      OnActiveSec = "180s";
      Unit = "rollback-gate.service";
    };
  };
}
